INSERT OR IGNORE INTO reels (equipmentName, equipmentType, category, subCategory, model, description, transmissionRatio, transmissionRatioStar, enginePower, lineSpeed, lineSpeedStar, size, form, frictionForce, frictionForceStar, windingSpeed, test, testStar, levelReq, spoolCapacity, obtainMethod, rating, adaptWeight, adaptWeightStar, goldPrice, silverPrice, lockTension, lockTensionStar, saltwaterResistant) VALUES ('Electro Raptor', '渔轮', '动力鼓轮', 'Electro Raptor', 'Electro Raptor 20', '电动猛禽系列鼓轮是专为垂钓者在深海恶劣的条件下捕捞大型稀有鱼类而设计的。这些轮子具备强大的性能，且极易操作，让您在对付深水中的强大鱼类时轻松省力。此系列鼓轮采用坚固的重型防水外壳，即便在极端环境下也能始终保持稳定的性能表现。其搭载了高效无刷电机，能够提供卓越的拉力和收线速度。', '3.2:1', 0, '33kg', '', 0, '20', '动力辅助鼓轮', '31.7kg', 0, '180米/分钟', '', 0, '32', '', '', '', '≥40.5g', 0, '245.74', '71988.6', '368±10kg', 0, '💧');
